from __future__ import annotations

import weakref


class ObjectRegistry:
    def __init__(self):
        self.refs = {}

    def register(self, key: str, obj):
        self.refs[key] = weakref.ref(obj)

    def get(self, key: str):
        if key not in self.refs:
            return None
        return self.refs[key]()

    def cleanup(self):
        for key in list(self.refs):
            if self.refs[key]() is None:
                del self.refs[key]

